from collections import Counter
from typing import List

class Solution:
    def minStickers(self, stickers: List[str], target: str) -> int:
        stickers = [Counter(sticker) for sticker in stickers]
        memo = dict()

        def dfs(target):
            if not target:
                return 0
            if target in memo:
                return memo[target]
            ans = float('inf')
            cnt = Counter(target)
            for sticker in stickers:
                if target[0] not in sticker:
                    continue
                tmp = dfs(''.join([c * (cnt[c] - sticker.get(c, 0)) for c in cnt]))
                if tmp != -1:
                    ans = min(ans, tmp + 1)
            memo[target] = ans if ans != float('inf') else -1
            return memo[target]

        return dfs(target)
